-- Stock initial (quantités variées pour tests caisse / alertes)
INSERT INTO stock_levels (id, product_id, quantity, is_synced)
SELECT uuid_generate_v4(), p.id,
       (5 + (ascii(substring(p.barcode from 8 for 1)) % 40))::int,
       FALSE
FROM products p
WHERE p.barcode LIKE 'TEST-%'
ON CONFLICT (product_id) DO UPDATE SET
  quantity = EXCLUDED.quantity,
  updated_at = NOW();
